import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { sortFightersByRank } from './matchScore';
import { setupPushRegistration } from './pushRegistration';
import { cityToCountry, filterCitiesByCountry } from './cityCountry';
import { autoFilterCandidates } from './autoFilters';
const Globe=lazy(()=>import('react-globe.gl'));

function UserGlobe({darkMode,onClose,SUPA_URL,SUPA_KEY}){
  const globeRef=useRef();
  const [points,setPoints]=useState([]);
  const [loading,setLoading]=useState(true);

  useEffect(()=>{
    let active=true;
    (async()=>{
      try{
        const res=await fetch(SUPA_URL+'/rest/v1/profiles?select=lat,lon,city&banned=eq.false&lat=not.is.null&lon=not.is.null',{
          headers:{apikey:SUPA_KEY,Authorization:'Bearer '+SUPA_KEY}
        });
        const data=await res.json();
        if(active&&Array.isArray(data)){
          // Mehrere Nutzer in derselben Stadt zu einem Punkt zusammenfassen
          // Stadt-Ebene-Rundung (~5km Raster) — bewusst KEINE exakten Koordinaten,
          // damit kein einzelner Nutzer auf seine genaue Adresse zurückverfolgbar ist.
          const CITY_GRID=0.05; // ca. 5km bei mittleren Breitengraden
          const seen={};
          const pts=[];
          data.forEach(d=>{
            if(!d.lat||!d.lon)return;
            const roundedLat=Math.round(d.lat/CITY_GRID)*CITY_GRID;
            const roundedLon=Math.round(d.lon/CITY_GRID)*CITY_GRID;
            const key=roundedLat+'_'+roundedLon;
            if(seen[key]){seen[key].count++;}
            else{const p={lat:roundedLat,lng:roundedLon,city:d.city||'',count:1};seen[key]=p;pts.push(p);}
          });
          setPoints(pts);
        }
      }catch(e){console.error('Globe-Daten laden fehlgeschlagen',e);}
      if(active)setLoading(false);
    })();
    return()=>{active=false;};
  },[SUPA_URL,SUPA_KEY]);

  useEffect(()=>{
    let cancelled=false;
    let attempts=0;
    function trySetup(){
      if(cancelled)return;
      attempts++;
      if(globeRef.current&&globeRef.current.controls){
        // Kamera auf Mitteleuropa ausrichten, damit Nutzer direkt sichtbar sind
        globeRef.current.pointOfView({lat:48,lng:9,altitude:1.6},0);
        const controls=globeRef.current.controls();
        if(controls){
          controls.autoRotate=false;
          controls.enableZoom=true;
          controls.minDistance=20;   // sehr tiefes Reinzoomen erlaubt
          controls.maxDistance=800;
          controls.zoomSpeed=1.1;
          controls.update&&controls.update();
        }
        return; // erfolgreich, Polling beenden
      }
      if(attempts<40){ // bis zu ~4 Sekunden lang erneut versuchen
        setTimeout(trySetup,100);
      }
    }
    trySetup();
    return()=>{cancelled=true;};
  },[points]);

  return(
    <div style={{position:'fixed',inset:0,background:'#000',zIndex:600,display:'flex',flexDirection:'column'}}>
      <div style={{position:'absolute',top:'calc(16px + env(safe-area-inset-top))',right:16,zIndex:10}}>
        <button onClick={onClose} style={{width:38,height:38,borderRadius:19,background:'rgba(255,255,255,0.12)',border:'none',color:'#fff',fontSize:18,cursor:'pointer'}}>✕</button>
      </div>
      <div style={{position:'absolute',top:'calc(16px + env(safe-area-inset-top))',left:16,zIndex:10,color:'#fff',fontFamily:'Rajdhani,sans-serif'}}>
        <div style={{fontSize:13,letterSpacing:2,color:'rgba(255,255,255,0.6)'}}>FIGHTER WELTWEIT</div>
        <div style={{fontSize:22,fontWeight:700,color:'#f5a623'}}>{points.reduce((s,p)=>s+p.count,0)} FIGHTER</div>
      </div>
      <div style={{flex:1,display:'flex',alignItems:'center',justifyContent:'center'}}>
        {loading?(
          <div style={{color:'rgba(255,255,255,0.5)',fontFamily:'Rajdhani,sans-serif',fontSize:16}}>Lädt Globus...</div>
        ):(
          <Suspense fallback={<div style={{color:'rgba(255,255,255,0.5)'}}>Lädt...</div>}>
            <Globe
              ref={globeRef}
              width={window.innerWidth}
              height={window.innerHeight}
              backgroundColor='#000000'
              globeImageUrl='https://raw.githubusercontent.com/vasturiano/three-globe/master/example/img/earth-night.jpg'
              pointResolution={12}
              bumpImageUrl='//unpkg.com/three-globe/example/img/earth-topology.png'
              pointsData={points}
              pointLat='lat'
              pointLng='lng'
              pointColor={()=>'#f5a623'}
              pointAltitude={0.008}
              pointRadius={d=>0.06+Math.min(d.count*0.02,0.14)}
              pointLabel={d=>`${d.city||''} · ${d.count} Fighter`}
              atmosphereColor='#f5a623'
              atmosphereAltitude={0.18}
            />
          </Suspense>
        )}
      </div>
    </div>
  );
}

const SUPA_URL = 'https://uykdrmymjvqgebsmndme.supabase.co';
const ADMIN_ID = '1a697731-458d-4559-a4cf-a89d3150bfa5';
// SUPA_SERVICE_KEY wurde entfernt - der Vollzugriffsschluessel liegt jetzt
// ausschliesslich sicher auf dem Server (admin-proxy Edge Function Secret),
// nicht mehr im Client-Code.
const SUPA_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InV5a2RybXltanZxZ2Vic21uZG1lIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzY2NzgzNDMsImV4cCI6MjA5MjI1NDM0M30.evhJ-C3jNPkcofVMOR50HHKR9KZ3w1k2TmY-N3jQFzk';

export async function authSignUp(email, password) {
  const r = await fetch(SUPA_URL + '/auth/v1/signup', {
    method: 'POST', headers: { 'Content-Type': 'application/json', apikey: SUPA_KEY },
    body: JSON.stringify({ email, password, options: { emailRedirectTo: 'https://fighterapp.de' } }),
  });
  return r.json();
}
export async function authSignIn(email, password) {
  const r = await fetch(SUPA_URL + '/auth/v1/token?grant_type=password', {
    method: 'POST', headers: { 'Content-Type': 'application/json', apikey: SUPA_KEY },
    body: JSON.stringify({ email, password }),
  });
  return r.json();
}
export async function authSignOut(token) {
  await fetch(SUPA_URL + '/auth/v1/logout', {
    method: 'POST', headers: { 'Content-Type': 'application/json', apikey: SUPA_KEY, Authorization: 'Bearer ' + token },
  });
}
function hdr(token) {
  return { 'Content-Type': 'application/json', apikey: SUPA_KEY, Authorization: 'Bearer ' + (token || SUPA_KEY) };
}
export async function dbInsert(table, data, token) {
  const r = await fetch(SUPA_URL + '/rest/v1/' + table, {
    method: 'POST', headers: { ...hdr(token), Prefer: 'return=representation' }, body: JSON.stringify(data),
  });
  return r.json();
}
export async function dbUpdate(table, data, query, token) {
  const r = await fetch(SUPA_URL + '/rest/v1/' + table + '?' + query, {
    method: 'PATCH', headers: { ...hdr(token), Prefer: 'return=representation' }, body: JSON.stringify(data),
  });
  return r.json();
}
export async function dbSelect(table, query, token) {
  const r = await fetch(SUPA_URL + '/rest/v1/' + table + (query ? '?' + query : ''), { headers: hdr(token) });
  return r.json();
}
// Sichere Admin-Schleuse: ersetzt direkte Aufrufe mit dem Vollzugriffs-
// schluessel. Der Schluessel selbst liegt nur noch serverseitig in der
// admin-proxy Edge Function - hier wird nur der eigene, normale Nutzer-
// Token mitgeschickt, den der Server dann selbst gegen die Admin-ID prueft.
export async function adminFetch(url, options = {}, userToken) {
  const path = url.replace(SUPA_URL, '');
  const extraHeaders = { ...(options.headers || {}) };
  delete extraHeaders.apikey;
  delete extraHeaders.Authorization;
  delete extraHeaders['Content-Type'];
  return fetch(SUPA_URL + '/functions/v1/admin-proxy', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', apikey: SUPA_KEY, Authorization: 'Bearer ' + SUPA_KEY },
    body: JSON.stringify({
      userToken,
      path,
      method: options.method || 'GET',
