    if(!p||p.clientX===undefined)return;
    const dx=p.clientX-start.x;
    const dy=p.clientY-start.y;
    // Immer horizontal updaten - auch bei leicht schrägen Swipes
    if(Math.abs(dx)>10)setOffset({x:dx,y:dy*0.2});
